63	// timedOut reports whether this operator command failed because it could not
64	// acquire the tracker lock in time (the "tracker lock timeout" error string is
65	// emitted by lockTimeoutError in internal/agent/tracker_lock.go).
66	func (c operatorCommand) timedOut() bool {
67		return strings.Contains(c.output, "tracker lock timeout")
68	}
