93	// TestIntegration_MultiWorkerLockContention_5Workers proves the scenario runs
94	// to completion: 5 `ddx work --watch` worker processes were spawned and all 20
95	// operator bead commands executed.
96	func TestIntegration_MultiWorkerLockContention_5Workers(t *testing.T) {
97		res := contentionScenario(t)
98		if res.workersSpawned != workerCount {
99			t.Fatalf("expected %d ddx work --watch worker processes, spawned %d", workerCount, res.workersSpawned)
100		}
101		if len(res.operatorOutput) != operatorCount {
102			t.Fatalf("expected %d operator bead commands to run, got %d", operatorCount, len(res.operatorOutput))
103		}
104		// At least one lock acquisition must have been observed, otherwise the p99
105		// assertions below would be vacuously true.
106		if len(res.indexHoldMS) == 0 && len(res.trackerHoldMS) == 0 {
107			t.Fatal("no lock acquisitions recorded; workers did not exercise the instrumented lock seams")
108		}
109	}
