111	// TestIntegration_MultiWorkerLockContention_P99IndexLockUnderCap asserts the
112	// p99 .git/index.lock hold time across all acquisitions is under the cap.
113	func TestIntegration_MultiWorkerLockContention_P99IndexLockUnderCap(t *testing.T) {
114		res := contentionScenario(t)
115		if len(res.indexHoldMS) == 0 {
116			t.Fatal("no index.lock acquisitions recorded")
117		}
118		p99 := percentile(res.indexHoldMS, 0.99)
119		capMS := float64(lockmetrics.DefaultIndexLockCap.Milliseconds())
120		if p99 >= capMS {
121			t.Fatalf("p99 index.lock hold %.0fms >= cap %.0fms (n=%d, max=%.0fms)",
122				p99, capMS, len(res.indexHoldMS), maxFloat(res.indexHoldMS))
123		}
124	}
