384	// percentile returns the nearest-rank percentile (p in [0,1]) of values.
385	func percentile(values []float64, p float64) float64 {
386		if len(values) == 0 {
387			return 0
388		}
389		sorted := append([]float64(nil), values...)
390		sort.Float64s(sorted)
391		rank := int(math.Ceil(p*float64(len(sorted)))) - 1
392		if rank < 0 {
393			rank = 0
394		}
395		if rank >= len(sorted) {
396			rank = len(sorted) - 1
397		}
398		return sorted[rank]
399	}
