411	// createBeads creates n beads via `ddx bead create` and returns their IDs.
412	func createBeads(bin, proj string, env []string, n int, titlePrefix string) ([]string, error) {
413		ids := make([]string, 0, n)
414		for i := 0; i < n; i++ {
415			cmd := exec.Command(bin, "bead", "create", fmt.Sprintf("%s %d", titlePrefix, i+1),
416				"--priority", "1", "--description", "do work", "--acceptance", "done")
417			cmd.Dir = proj
418			cmd.Env = env
419			out, err := cmd.CombinedOutput()
420			if err != nil {
421				return nil, fmt.Errorf("bead create %d: %v\n%s", i, err, out)
422			}
423			id := lastLine(string(out))
424			if id == "" {
425				return nil, fmt.Errorf("bead create %d produced no id:\n%s", i, out)
426			}
427			ids = append(ids, id)
428		}
429		return ids, nil
430	}
