432	// stopWorkers interrupts each still-running worker and waits for it to exit,
433	// killing any that do not stop promptly.
434	func stopWorkers(workers []*exec.Cmd) {
435		for _, cmd := range workers {
436			if cmd.Process == nil || (cmd.ProcessState != nil && cmd.ProcessState.Exited()) {
437				continue
438			}
439			_ = cmd.Process.Signal(os.Interrupt)
440		}
441		for _, cmd := range workers {
442			if cmd.Process == nil {
443				continue
444			}
445			done := make(chan struct{})
446			go func(c *exec.Cmd) {
447				_ = c.Wait()
448				close(done)
449			}(cmd)
450			select {
451			case <-done:
452			case <-time.After(10 * time.Second):
453				_ = cmd.Process.Kill()
454				<-done
455			}
456		}
457	}
