493	// lastLine returns the last non-empty trimmed line of s (the bead id printed by
494	// `ddx bead create`).
495	func lastLine(s string) string {
496		lines := strings.Split(strings.TrimSpace(s), "\n")
497		for i := len(lines) - 1; i >= 0; i-- {
498			if v := strings.TrimSpace(lines[i]); v != "" {
499				return v
500			}
501		}
502		return ""
503	}
