3	// concurrent_try_test.go — subprocess integration tests for concurrent ddx try
4	// invocations as required by TP-021-multi-worker-try-reliability.md.
5	//
6	// Three test functions are provided (each satisfying one TP-021 integration AC):
7	//
8	//   TestIntegration_ConcurrentTryDistinctBeads_LocalClone
9	//   TestIntegration_ConcurrentTrySameBead_OneClaimWins
10	//   TestIntegration_ConcurrentTryPreserveRefsUnique
11	//
12	// All three use testutils.BuildDDxBinary, fixture repositories, and the
13	// deterministic `script` harness with an isolated HOME/XDG_DATA_HOME. None of
14	// them require network access or external agent CLIs.
15	
16	import (
17		"bytes"
18		"os"
19		"os/exec"
20		"path/filepath"
21		"strings"
22		"sync"
23		"testing"
