30	// subprocessEnvFor builds the minimal isolated subprocess environment used by
31	// all concurrent-try tests. HOME and XDG_DATA_HOME are set to fresh temp dirs
32	// so workers do not read real developer config or register with the local
33	// ddx-server. PATH is stripped to git + standard system directories so agent
34	// CLIs (codex, claude, gemini) cannot be discovered and daemonised.
35	func subprocessEnvFor(t *testing.T, bin string) (env []string, home, xdg string) {
36		t.Helper()
37		gitPath, err := exec.LookPath("git")
38		if err != nil {
39			t.Fatalf("subprocessEnvFor: locate git binary: %v", err)
40		}
41		minimalPATH := strings.Join(
42			[]string{filepath.Dir(gitPath), filepath.Dir(bin), "/usr/bin", "/bin", "/usr/sbin", "/sbin"},
43			string(os.PathListSeparator),
44		)
45		home = t.TempDir()
46		xdg = t.TempDir()
47		env = []string{
48			"HOME=" + home,
49			"XDG_DATA_HOME=" + xdg,
50			"PATH=" + minimalPATH,
51			"GIT_CONFIG_SYSTEM=/dev/null",
52			"GIT_TERMINAL_PROMPT=0",
53		}
54		return env, home, xdg
55	}
