57	// spawnTry launches a single `ddx try <beadID>` subprocess and returns the
58	// started *exec.Cmd with stdout/stderr captured in buf. Callers must call
59	// cmd.Wait() to collect the exit code and release resources. extraFlags are
60	// appended to the base flags (e.g. "--from <sha>").
61	func spawnTry(bin, proj, beadID, harness, directive string, env []string, extraFlags ...string) (*exec.Cmd, *bytes.Buffer) {
62		buf := &bytes.Buffer{}
63		args := []string{"try", beadID,
64			"--harness", harness,
65			"--model", directive,
66			"--attempt-backend", "local-clone",
67			"--no-review", "--no-review-i-know-what-im-doing",
68			"--project", proj,
69		}
70		args = append(args, extraFlags...)
71		cmd := exec.Command(bin, args...)
72		cmd.Dir = proj
73		cmd.Env = env
74		cmd.Stdout = buf
