113	// gitRunIn runs a git command in dir and returns its output, fatally failing t
114	// on error. env defaults to the current process environment.
115	func gitRunIn(t *testing.T, dir string, args ...string) string {
116		t.Helper()
117		cmd := exec.Command("git", append([]string{"-C", dir}, args...)...)
118		cmd.Env = append(os.Environ(), "GIT_CONFIG_SYSTEM=/dev/null")
119		out, err := cmd.CombinedOutput()
120		if err != nil {
121			// An "empty commit" is not a test failure.
122			if strings.Contains(string(out), "nothing to commit") {
123				return string(out)
124			}
125			t.Fatalf("git %v in %s: %v\n%s", args, dir, err, out)
126		}
127		return strings.TrimSpace(string(out))
128	}
