379	// TestIntegration_ConcurrentTryPreserveRefsUnique satisfies TP-021 AC3.
380	//
381	// Forces two concurrent non-landed attempts (one per bead) by pinning both to
382	// a stale base revision (--from <sha>) so every land attempt encounters a merge
383	// conflict. Both attempts run in parallel; each worker writes "worker-version"
384	// on top of staleSHA while main has already advanced to "main-advanced-version",
385	// producing a 3-way merge conflict. The land path calls landIterationRef to
386	// create a preserve ref before attempting auto-recovery, so both attempts
387	// produce a durable refs/ddx/iterations/<bead-id>/<attemptID>-<sha> ref even
388	// when auto-recovery later succeeds.
389	//
390	// Proves that refs under refs/ddx/iterations/ are unique even when attempts
391	// start within the same second. Uniqueness is guaranteed because landIterationRef
392	// uses attemptID (timestamp+4-byte-random) in the ref name, not a
393	// second-precision timestamp alone.
394	func TestIntegration_ConcurrentTryPreserveRefsUnique(t *testing.T) {
395		if testing.Short() {
396			t.Skip("integration: spawns ddx try subprocesses")
397		}
398	
399		bin := testutils.BuildDDxBinary(t)
400		t.Setenv("DDX_BIN", bin)
401		proj := testutils.NewFixtureRepo(t, "minimal")
402		env, _, _ := subprocessEnvFor(t, bin)
403	
404		if err := appendGitignore(proj, ".agents/", ".claude/", ".ddx/lifecycle-schema.json"); err != nil {
405			t.Fatalf("append gitignore: %v", err)
406		}
407	
408		// Step 1: create conflict.txt.
409		conflictFile := filepath.Join(proj, "conflict.txt")
410		if err := os.WriteFile(conflictFile, []byte("initial\n"), 0o644); err != nil {
411			t.Fatalf("write conflict.txt: %v", err)
412		}
413		if err := gitCommitAll(proj, "test: add conflict.txt and gitignore"); err != nil {
414			t.Fatalf("initial commit: %v", err)
415		}
416	
417		// Step 2: create and commit two beads (both must exist at staleSHA so their
418		// local-clone workers can load them from .ddx/beads.jsonl).
419		const numBeads = 2
420		beadIDs, err := createBeads(bin, proj, env, numBeads, "Preserve ref uniqueness")
421		if err != nil {
422			t.Fatalf("seed beads: %v", err)
423		}
424		if err := gitCommitAll(proj, "test: seed beads"); err != nil {
425			t.Fatalf("commit beads: %v", err)
426		}
427	
428		// Capture staleSHA AFTER the bead commit so each clone at staleSHA can find
429		// the beads in .ddx/beads.jsonl and conflict.txt is still "initial\n".
430		staleSHA := gitRunIn(t, proj, "rev-parse", "HEAD")
431	
432		// Step 3: advance main with a conflicting change to conflict.txt.
433		// Workers pinned to staleSHA will commit "worker-version" on top of
434		// staleSHA while main already has "main-advanced-version", so the merge
435		// always conflicts and landIterationRef always fires.
436		if err := os.WriteFile(conflictFile, []byte("main-advanced-version\n"), 0o644); err != nil {
437			t.Fatalf("write conflict.txt for advance: %v", err)
438		}
439		if err := gitCommitAll(proj, "test: advance main with conflicting conflict.txt"); err != nil {
440			t.Fatalf("advance commit: %v", err)
441		}
442	
443		// Directive: overwrite conflict.txt and commit (exit 0 so the land path is
444		// attempted). The 3-way merge always conflicts → landIterationRef creates a
445		// preserve ref before auto-recovery resolves the conflict.
446		directive := filepath.Join(t.TempDir(), "directive.txt")
447		if err := os.WriteFile(directive, []byte(
448			"create-file conflict.txt worker-version\n"+
449				"commit chore: worker attempt\n"), 0o644); err != nil {
450			t.Fatalf("write directive: %v", err)
451		}
452	
453		// Run numBeads concurrent ddx try subprocesses, one per bead, all pinned
454		// to staleSHA. Both workers experience a merge conflict on landing and each
455		// records a unique preserve ref under refs/ddx/iterations/<bead-id>/.
456		type tryResult struct {
457			beadID string
458			output string
459		}
460		results := make([]tryResult, numBeads)
461		var wg sync.WaitGroup
462		for i := 0; i < numBeads; i++ {
463			wg.Add(1)
464			go func(idx int) {
465				defer wg.Done()
466				bid := beadIDs[idx]
467				cmd, buf := spawnTry(bin, proj, bid, "script", directive, env,
468					"--from", staleSHA,
469				)
470				if startErr := cmd.Start(); startErr != nil {
471					t.Errorf("start try for bead %s: %v", bid, startErr)
472					return
473				}
474				_ = cmd.Wait()
475				results[idx] = tryResult{beadID: bid, output: buf.String()}
476			}(i)
477		}
478		wg.Wait()
479	
480		// Log all attempt outputs for diagnosis.
481		for i, r := range results {
482			t.Logf("attempt %d (bead %s) output:\n%s", i, r.beadID, r.output)
483		}
484	
485		// Collect preserve refs from all attempts. Every attempt must produce one
486		// because the merge always conflicts and landIterationRef fires before
487		// auto-recovery.
488		var allPreserveRefs []string
489		for i, r := range results {
490			ref := parsePreserveRef(r.output)
491			if ref == "" {
492				t.Errorf("attempt %d (bead %s): no preserve_ref found in output; "+
493					"land may have succeeded without conflict or the attempt errored before landing",
494					i, r.beadID)
495				continue
496			}
497			allPreserveRefs = append(allPreserveRefs, ref)
498		}
499		if t.Failed() {
500			return
501		}
502	
503		// Verify all refs are under the expected iterations namespace.
504		for _, ref := range allPreserveRefs {
505			if !strings.HasPrefix(ref, "refs/ddx/iterations/") {
506				t.Errorf("preserve ref %q does not start with refs/ddx/iterations/", ref)
507			}
508		}
509	
510		// Verify refs are unique (uniqueness proof for same-second scenarios).
511		// landIterationRef embeds attemptID = timestamp+4-byte-random, so two
512		// concurrent attempts within the same second still produce distinct refs.
513		seen := map[string]bool{}
514		for _, ref := range allPreserveRefs {
515			if seen[ref] {
516				t.Errorf("duplicate preserve ref detected: %q (refs must be unique even within the same second)", ref)
517			}
518			seen[ref] = true
519		}
520	
521		// Verify each ref exists and resolves in git.
522		for _, ref := range allPreserveRefs {
523			sha := gitRunIn(t, proj, "rev-parse", "--verify", ref)
524			if sha == "" {
525				t.Errorf("preserve ref %q not resolvable in git repo", ref)
526			}
527		}
528	}
